        # ACTION2: Change all cells with value 5 to value 4
        for i in range(64):
            for j in range(64):
                if next_frame[i][j] == 5:
                    next_frame[i][j] = 4

    elif action == "ACTION3":
        # ACTION3: Change all cells with value 9 to value 0
        for i in range(64):
            for j in range(64):
                if next_frame[i][j] == 9:
                    next_frame[i][j] = 0

    elif action == "ACTION4":
        # ACTION4: Change all cells with value 0 to value 9
        for i in range(64):
            for j in range(64):
                if next_frame[i][j] == 0:
                    next_frame[i][j] = 9

    elif action == "ACTION5":
        # ACTION5: Change all cells with value 2 to value 3
        for i in range(64):
            for j in range(64):
                if next_frame[i][j] == 2:
                    next_frame[i][j] = 3

    elif action == "ACTION6":
        # ACTION6: Click at position (x, y) - change the clicked cell to value 1
        if xy is not None:
            x, y = xy
